// Tally adapter. EDIT LABELS to match your Tally form.
const LABELS = { name: 'Imię i nazwisko', email: 'E-mail', phone: 'Telefon', message: 'Wiadomość' };
const b = $input.first().json.body || $input.first().json;
const fields = (b.data && b.data.fields) || [];
const get = l => { const f = fields.find(f => (f.label||'').trim().toLowerCase() === l.toLowerCase());
  return f ? ((f.value && f.value.text) || f.value) : undefined; };
return [{ json: { name: get(LABELS.name)||'', email_raw: String(get(LABELS.email)||''),
  phone_raw: String(get(LABELS.phone)||''), message: String(get(LABELS.message)||''),
  channel: 'formularz', source: 'google', booking: null } }];

// Contact Form 7 adapter (WP plugin 'CF7 to Webhook' posts flat JSON of form fields).
// EDIT FIELDS to match your CF7 field names (check one real payload in the execution log).
const FIELDS = { name: 'your-name', email: 'your-email', phone: 'your-phone', message: 'your-message' };
const b = $input.first().json.body || $input.first().json;
return [{ json: { name: String(b[FIELDS.name]||''), email_raw: String(b[FIELDS.email]||''),
  phone_raw: String(b[FIELDS.phone]||''), message: String(b[FIELDS.message]||''),
  channel: 'formularz', source: 'google', booking: null } }];

// MS Bookings adapter. Bookings has no native outbound webhook - route it via
// Power Automate ('When an appointment is created' -> HTTP POST here) and EDIT the map.
const b = $input.first().json.body || $input.first().json;
return [{ json: { name: String(b.customerName||''), email_raw: String(b.customerEmail||''),
  phone_raw: String(b.customerPhone||''), message: String(b.customerNotes||''),
  channel: 'bookings', source: 'google',
  booking: { title: `Discovery — ${b.customerName||'nowy klient'}`,
             starts_at: b.startTime || null, ends_at: b.endTime || null } } }];

// Shared normalization for all sources.
const PUBLIC = ['gmail.com','googlemail.com','wp.pl','o2.pl','onet.pl','op.pl','interia.pl',
  'icloud.com','me.com','outlook.com','hotmail.com','live.com','proton.me','protonmail.com',
  'yahoo.com','gazeta.pl','poczta.fm'];
const j = $input.first().json;
const email = j.email_raw.trim().toLowerCase();
const domain = email.split('@')[1] || '';
return [{ json: { ...j, email,
  email_query: email || 'no-email@none.invalid',   // matches nothing when empty
  public_domain: !domain || PUBLIC.includes(domain),
  has_booking: !!j.booking } }];

// Matching cascade. Tier 2 (company domain) is intentionally absent here:
// creating a lead fires the existing W5 webhook which handles it.
const inp = $('Normalize').first().json;
const byEmail = ($('Find leads by email').first().json.list || [])
  .sort((a, b) => b.Id - a.Id);                       // newest first
const openLeads = $('Get open leads').first().json.list || [];
const fold = s => String(s||'').toLowerCase().normalize('NFD')
  .replace(/[\u0300-\u036f]/g, '').replace(/ł/g, 'l').trim();
const phone9 = s => String(s||'').replace(/\D/g, '').slice(-9);

const base = { contact_name: inp.name || 'Unknown', contact_email: inp.email,
  contact_phone: inp.phone_raw, notes: inp.message, source: inp.source,
  contact_channel: inp.channel, stage: 'new', state: 'open',
  qualification: 'unqualified', offer_prep_status: 'none',
  company_match_status: 'none', duplicate_check: 'none',
  owner: 'przemek.fidzina@coaction-test.pl', enquiry_no: 1,
  type: inp.public_domain ? 'B2C' : 'B2B' };

let tier, extra = {};
const open = byEmail.find(l => l.state === 'open');
if (open) { tier = 'tier1_open'; extra = { match: open }; }
else if (byEmail.length) {
  tier = 'tier1_closed';
  extra = { old: byEmail[0] };
  base.enquiry_no = byEmail.length + 1;
  base.source = 'powrot_klienta';
} else {
  const nameOk = fold(inp.name).length > 4;
  const cand = openLeads.find(l =>
    (nameOk && fold(l.contact_name) === fold(inp.name)) ||
    (phone9(inp.phone_raw).length === 9 && phone9(l.contact_phone) === phone9(inp.phone_raw)));
  if (cand) { tier = 'tier3'; extra = { cand }; base.duplicate_check = 'pending_confirmation'; }
  else if ((inp.message || '').trim().length > 30) tier = 'llm';
  else tier = 'tier5';
}
return [{ json: { tier, base, ...extra, has_booking: inp.has_booking,
  booking: inp.booking, message: inp.message } }];

// tier1_open: no new lead - task + activity on the existing one.
const d = $('Cascade decision').item.json;
const m = d.match;
const owner = (Array.isArray(m.owner) ? m.owner[0] && m.owner[0].email
              : m.owner && m.owner.email) || 'przemek.fidzina@coaction-test.pl';
return [{ json: { final_lead_id: m.Id,
  task: { title: `Klient napisał ponownie: ${m.contact_name}`, status: 'todo',
          priority: 'high', assignee: owner, created_by_flow: 'W4',
          description: `lead:${m.Id}\n---\n${d.message}` },
  activity: { summary: `Returning enquiry on open lead: ${m.contact_name}`,
              type: 'lead_created', flow: 'W4', triggered_by: 'system',
              payload: JSON.stringify({ lead_id: m.Id, tier: 'tier1_open',
                                        message: d.message.slice(0, 500) }) } } }];

// tier1_closed: lead was created in the previous node; carry ids + old-lead ref.
const d = $('Cascade decision').item.json;
const newId = $input.first().json.Id;
return [{ json: { final_lead_id: newId, old_id: d.old.Id,
  task: { title: `Powracający klient (${d.base.enquiry_no}. zapytanie): ${d.base.contact_name}`,
          status: 'todo', priority: 'high', assignee: 'przemek.fidzina@coaction-test.pl',
          created_by_flow: 'W4', description: `lead:${newId}\npoprzedni lead: #${d.old.Id}` },
  activity: { summary: `Returning client, new opportunity (prev lead #${d.old.Id})`,
              type: 'lead_created', flow: 'W4', triggered_by: 'system',
              payload: JSON.stringify({ lead_id: newId, tier: 'tier1_closed',
                                        previous_lead_id: d.old.Id,
                                        enquiry_no: d.base.enquiry_no }) } } }];

// Prepare company re-link for the returning client (may be empty).
const ids = ($input.first().json.list || []).map(r => ({ Id: r.Id }));
return [{ json: { ...$('Finish tier1_closed').item.json, company_ids: ids } }];

// tier3: lead created with duplicate_check=pending; prepare suggestion payloads.
const d = $('Cascade decision').item.json;
const newId = $input.first().json.Id;
return [{ json: { final_lead_id: newId, cand_id: d.cand.Id,
  comment: `Possible duplicate of lead #${d.cand.Id} (${d.cand.contact_name}) - ` +
           `matched by name/phone. Confirm via 'duplicate_check' field.`,
  task: { title: `Potwierdź dopasowanie: ${d.base.contact_name} ↔ #${d.cand.Id}`,
          status: 'todo', priority: 'normal', assignee: 'przemek.fidzina@coaction-test.pl',
          created_by_flow: 'W4', description: `lead:${newId}` },
  activity: { summary: `Duplicate suggested: new lead vs #${d.cand.Id} (${d.cand.contact_name})`,
              type: 'company_match_suggested', flow: 'W4', triggered_by: 'system',
              payload: JSON.stringify({ lead_id: newId, candidate: d.cand.Id, tier: 'tier3' }) } } }];

// Run deterministic searches with the AI-extracted criteria (extractor, not judge).
const d = $('Cascade decision').item.json;
const openLeads = $('Get open leads').first().json.list || [];
const companies = $('Get companies').first().json.list || [];
const raw = $input.first().json;
const content = raw.choices && raw.choices[0] && raw.choices[0].message
  && raw.choices[0].message.content || '{}';
let c;
try { c = JSON.parse(content.replace(/```json|```/g, '').trim()); }
catch (e) { c = {}; }
const fold = s => String(s||'').toLowerCase().normalize('NFD')
  .replace(/[\u0300-\u036f]/g, '').replace(/ł/g, 'l').trim();
const phone9 = s => String(s||'').replace(/\D/g, '').slice(-9);
const emails = (c.emails||[]).map(e => e.toLowerCase());
const phones = (c.phones||[]).map(phone9).filter(p => p.length === 9);
const names  = (c.person_names||[]).map(fold).filter(n => n.length > 4);
const comps  = (c.company_names||[]).map(fold).filter(n => n.length > 2);
const domains = emails.map(e => e.split('@')[1]).filter(Boolean);

const lead = openLeads.find(l =>
  emails.includes(String(l.contact_email||'').toLowerCase()) ||
  phones.includes(phone9(l.contact_phone)) ||
  names.includes(fold(l.contact_name)));
const company = !lead && companies.find(co =>
  comps.some(n => fold(co.name).includes(n)) ||
  domains.some(dm => String(co.domains||'').toLowerCase().includes(dm)));

return [{ json: { ...d, found: !!(lead || company),
  cand_lead_id: lead ? lead.Id : null, cand_lead_name: lead ? lead.contact_name : null,
  cand_company_id: company ? company.Id : null, cand_company_name: company ? company.name : null,
  criteria: c, type_signal: c.type_signal || null } }];

// AI-assisted match found: lead was just created; prepare suggestion payloads.
const d = $('Match extracted criteria').item.json;
const newId = $input.first().json.Id;
const target = d.cand_lead_id
  ? `lead #${d.cand_lead_id} (${d.cand_lead_name})`
  : `company '${d.cand_company_name}'`;
return [{ json: { final_lead_id: newId,
  cand_lead_id: d.cand_lead_id, cand_company_id: d.cand_company_id,
  comment: `AI-extracted criteria matched ${target}. Reasoning: ` +
           `${(d.criteria.reasoning||'').slice(0,300)}. Confirm via 'duplicate_check' / 'company_match_status'.`,
  task: { title: `Zaklasyfikuj (AI, do potwierdzenia): ${d.base.contact_name}`,
          status: 'todo', priority: 'normal', assignee: 'przemek.fidzina@coaction-test.pl',
          created_by_flow: 'W4', description: `lead:${newId}` },
  activity: { summary: `AI criteria matched ${target}`,
              type: 'company_match_suggested', flow: 'W4', triggered_by: 'system',
              payload: JSON.stringify({ lead_id: newId, criteria: d.criteria,
                cand_lead_id: d.cand_lead_id, cand_company_id: d.cand_company_id }) } } }];

// tier5 (also LLM-miss fallback): plain new lead.
const src = $('Match extracted criteria').isExecuted
  ? $('Match extracted criteria').item.json : $('Cascade decision').item.json;
const base = { ...src.base };
if (src.type_signal) base.type = src.type_signal;   // AI hint, human verifies anyway
return [{ json: { base } }];

const d = $('Prepare plain lead').item.json;
const newId = $input.first().json.Id;
return [{ json: { final_lead_id: newId,
  task: { title: `Zaklasyfikuj / pierwszy kontakt: ${d.base.contact_name}`, status: 'todo',
          priority: 'high', assignee: 'przemek.fidzina@coaction-test.pl', created_by_flow: 'W4',
          description: `lead:${newId}` },
  activity: { summary: `Lead created (no match): ${d.base.contact_name}`,
              type: 'lead_created', flow: 'W4', triggered_by: 'system',
              payload: JSON.stringify({ lead_id: newId, tier: 'tier5' }) } } }];
